from flask import Flask, request, current_app, send_file, redirect, url_for
from flask_login import LoginManager, UserMixin, login_user, logout_user, current_user, login_required
from flask_uploads import UploadSet, configure_uploads, IMAGES
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)
app.config['UPLOADED_PHOTOS_DEST'] = 'static/photos'
photos = UploadSet('photos', IMAGES)
configure_uploads(app, photos)

login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin):
    pass

@login_manager.user_loader
def load_user(user_id):
    return User()

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        # Implement your authentication logic here
        user = User()
        login_user(user)
        return redirect(url_for('profile'))
    return '''
        <!doctype html>
        <title>Login</title>
        <h1>Please sign in</h1>
        <form method=post>
            username: <input type=text name=username><br>
            password: <input type=password name=password><br>
            <input type=submit value=Sign me up>
        </form>
    '''

@app.route('/logout')
@login_required
def logout():
    logout_user()
    return redirect(url_for('login'))

@app.route('/profile', methods=['GET', 'POST'])
@login_required
def profile():
    if request.method == 'POST':
        file = request.files['photo']
        filename = secure_filename(file.filename)
        file.save(os.path.join(app.config['UPLOADED_PHOTOS_DEST'], filename))
        return send_file(os.path.join(app.config['UPLOADED_PHOTOS_DEST'], filename), as_attachment=True)
    return '''
        <!doctype html>
        <title>Profile</title>
        <h1>Upload your profile picture:</h1>
        <form method=post enctype=multipart/form-data>
            <input type=file name=photo><br>
            <input type=submit value=Upload>
        </form>
    '''

if __name__ == '__main__':
    app.run(debug=True)